-- PARTE 6/6 — conteúdo das iscas 25–29
update public.blog_templum_iscas set headline='PQO pronto pro<br><em>canteiro</em> e pra <em>auditoria</em>.', subhead='Plano de Qualidade da Obra com a estrutura que o PBQP-H exige, controle de serviços, inspeções, materiais e registros.', benefits='["<strong>Controle de serviços executados</strong> com critérios de aceitação.","<strong>Inspeções</strong> programadas e registradas.","Controle de <strong>materiais</strong> recebidos e estocados.","Registros <strong>auditáveis</strong> pelo PBQP-H."]'::jsonb, steps='[{"num":"01","title":"Serviços controlados","text":"Lista de serviços com critério de aceitação por etapa."},{"num":"02","title":"Inspeções","text":"Frequência, responsável e registro de cada inspeção."},{"num":"03","title":"Materiais","text":"Recebimento, estocagem e rastreabilidade."},{"num":"04","title":"Registros","text":"Trilha pronta para auditoria PBQP-H."}]'::jsonb, cta_title='PQO bem estruturado<br><em>passa</em> na auditoria.', cta_copy='Planilha pronta para construtoras certificadas ou em processo de certificação PBQP-H.', cta_items='["Aderente a PBQP-H níveis A e B","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-pqo-plano-de-qualidade-da-obra';
update public.blog_templum_iscas set headline='Perigos e riscos<br><em>mapeados</em>, antes<br>do <em>acidente</em>.', subhead='Identificação de perigos por função, avaliação de risco com matriz e hierarquia de controle, alinhada à NR-01 e ISO 45001.', benefits='["Identificação por <strong>função e tarefa</strong>.","Matriz com <strong>probabilidade × severidade</strong> automática.","<strong>Hierarquia de controle</strong> aplicada.","Base para <strong>PGR</strong> e ISO 45001."]'::jsonb, steps='[{"num":"01","title":"Função e tarefa","text":"Mapeamento por cargo e atividade."},{"num":"02","title":"Perigos","text":"Identificação por tipo: físico, químico, biológico, ergonômico, acidente."},{"num":"03","title":"Avaliação","text":"Matriz com cálculo automático de nível de risco."},{"num":"04","title":"Controle","text":"Plano de medida segundo hierarquia de controle."}]'::jsonb, cta_title='PGR e ISO 45001<br>começam <em>aqui</em>.', cta_copy='A planilha pode ser base direta para construção do PGR (NR-01) e do mapeamento exigido pela ISO 45001.', cta_items='["Aderente a NR-01 e ISO 45001","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-planilha-perigos-e-riscos';
update public.blog_templum_iscas set headline='Estoque <em>controlado</em><br>é caixa <em>liberado</em>.', subhead='Planilha de controle de estoque com entrada, saída, ponto de pedido, mínimo, máximo e indicadores de giro.', benefits='["<strong>Entrada e saída</strong> com cálculo automático de saldo.","<strong>Alerta de reposição</strong> quando atinge o mínimo.","<strong>Giro de estoque</strong> e curva ABC.","Pronta para <strong>pequenas e médias</strong> empresas."]'::jsonb, steps='[{"num":"01","title":"Cadastro","text":"Itens com código, descrição, unidade e fornecedor."},{"num":"02","title":"Movimentação","text":"Entrada, saída e ajuste com cálculo automático de saldo."},{"num":"03","title":"Parâmetros","text":"Mínimo, máximo e ponto de pedido por item."},{"num":"04","title":"Análise","text":"Giro, curva ABC e itens em ruptura."}]'::jsonb, cta_title='Estoque parado<br>é <em>dinheiro parado</em>.', cta_copy='Planilha pronta para PME, sem precisar de ERP nem fórmula complexa.', cta_items='["Pronta para uso imediato","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-controle-de-estoque';
update public.blog_templum_iscas set headline='Tartaruga turbinada,<br>mapeamento <em>completo</em><br>de processo.', subhead='O diagrama Tartaruga é a forma mais didática de mapear um processo. Esta versão turbinada inclui indicadores, riscos e controles na mesma vista.', benefits='["Estrutura clássica de <strong>entradas, saídas, recursos, controles</strong>.","Adição de <strong>indicadores</strong> e <strong>riscos</strong>.","Visão única do processo <strong>em uma página</strong>.","Usada em <strong>auditoria e treinamento</strong>."]'::jsonb, steps='[{"num":"01","title":"Identificação","text":"Nome do processo, dono e cliente interno."},{"num":"02","title":"Quadrantes","text":"Entradas, saídas, recursos e controles em uma vista."},{"num":"03","title":"Indicadores e riscos","text":"Camada adicional que enriquece o diagrama tradicional."},{"num":"04","title":"Análise crítica","text":"Espaço para revisão periódica e oportunidades."}]'::jsonb, cta_title='Processo em<br><em>uma página</em>.', cta_copy='Tartaruga turbinada é a planilha que substitui apresentação de 20 slides, direto, visual e auditável.', cta_items='["Aplicável a qualquer setor","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-tartaruga-turbinada';
update public.blog_templum_iscas set headline='Caixa sob <em>controle</em>,<br>decisão com <em>visibilidade</em>.', subhead='Planilha de fluxo de caixa simplificado: entradas, saídas, saldo do dia, saldo projetado e gestão de contas a pagar e receber.', benefits='["<strong>Saldo diário</strong> com projeção futura.","<strong>Contas a pagar e receber</strong> integradas.","Categorização por <strong>centro de custo</strong>.","Visão de <strong>30, 60, 90 dias</strong> à frente."]'::jsonb, steps='[{"num":"01","title":"Lançamentos","text":"Entrada, saída e categoria com saldo automático."},{"num":"02","title":"Projeção","text":"Saldo previsto considerando A Pagar e A Receber."},{"num":"03","title":"Categorias","text":"Centro de custo e tipo de despesa pré-configurados."},{"num":"04","title":"Painel mensal","text":"Visão consolidada por mês com gráficos."}]'::jsonb, cta_title='Caixa <em>previsto</em><br>caixa <em>controlado</em>.', cta_copy='Planilha simples e direta, feita para empresário que quer visibilidade sem complicação de ERP.', cta_items='["Pronta para uso imediato","Compatível com Google Sheets e Excel","Sem custo · sem compromisso"]'::jsonb, faq='[]'::jsonb where slug='planilha-fluxo-de-caixa';
